/**
 * Audit logging service for notification dispatch.
 *
 * Records every notification that is dispatched through the system,
 * capturing the notification details, priority, and channel used.
 */

import type { NotificationPriority } from './priority-router.js';

export interface AuditEntry {
  id: string;
  timestamp: Date;
  notificationType: string;
  recipient: string;
  subject: string;
  body: string;
  priority: NotificationPriority;
  channel: string;
}

let nextAuditId = 1;

function generateAuditId(): string {
  return `audit-${String(nextAuditId++).padStart(4, '0')}`;
}

export function resetAuditIdCounter(): void {
  nextAuditId = 1;
}

export class AuditService {
  private entries: AuditEntry[] = [];

  log(params: {
    notificationType: string;
    recipient: string;
    subject: string;
    body: string;
    priority: NotificationPriority;
    channel: string;
  }): AuditEntry {
    const entry: AuditEntry = {
      id: generateAuditId(),
      timestamp: new Date(),
      ...params,
    };
    this.entries.push(entry);
    return entry;
  }

  getEntries(): AuditEntry[] {
    return [...this.entries];
  }

  getEntriesForRecipient(recipient: string): AuditEntry[] {
    return this.entries.filter((e) => e.recipient === recipient);
  }

  getEntriesByChannel(channel: string): AuditEntry[] {
    return this.entries.filter((e) => e.channel === channel);
  }

  getEntriesByPriority(priority: NotificationPriority): AuditEntry[] {
    return this.entries.filter((e) => e.priority === priority);
  }

  getEntryCount(): number {
    return this.entries.length;
  }

  clear(): void {
    this.entries = [];
  }
}

/**
 * Notification preferences service.
 *
 * Allows per-user channel preferences that override the default
 * priority-based routing. For example, a user can choose to receive
 * all urgent notifications via email instead of SMS.
 */

import type { NotificationPriority } from './priority-router.js';

export type ChannelType = 'email' | 'sms' | 'webhook';

export class NotificationPreferencesService {
  private preferences = new Map<string, Map<NotificationPriority, ChannelType>>();

  setPreference(userId: string, priority: NotificationPriority, channel: ChannelType): void {
    let userPrefs = this.preferences.get(userId);
    if (!userPrefs) {
      userPrefs = new Map();
      this.preferences.set(userId, userPrefs);
    }
    userPrefs.set(priority, channel);
  }

  getPreference(userId: string, priority: NotificationPriority): ChannelType | undefined {
    return this.preferences.get(userId)?.get(priority);
  }

  removePreference(userId: string, priority: NotificationPriority): boolean {
    const userPrefs = this.preferences.get(userId);
    if (!userPrefs) return false;
    const deleted = userPrefs.delete(priority);
    if (userPrefs.size === 0) {
      this.preferences.delete(userId);
    }
    return deleted;
  }

  getUserPreferences(userId: string): Map<NotificationPriority, ChannelType> {
    return new Map(this.preferences.get(userId) ?? []);
  }

  clearPreferences(userId: string): void {
    this.preferences.delete(userId);
  }

  clear(): void {
    this.preferences.clear();
  }
}

