export class NotificationService {
  private logger = new Logger('NotificationService');
  private notifications: Notification[] = [];
  private priorityRouter: PriorityRouter | null;
  private auditService: AuditService | null;
  private preferencesService: NotificationPreferencesService | null;
  private channelRegistry = new Map<ChannelType, NotificationChannel>();

  constructor(
    private eventBus: EventBus,
    priorityRouter: PriorityRouter | null = null,
    auditService: AuditService | null = null,
    preferencesService: NotificationPreferencesService | null = null,
  ) {
    this.priorityRouter = priorityRouter;
    this.auditService = auditService;
    this.preferencesService = preferencesService;
    this.registerHandlers();
  }

  /**
   * Register a named channel so that user preferences can resolve to it.
   */
  registerChannel(type: ChannelType, channel: NotificationChannel): void {
    this.channelRegistry.set(type, channel);
  }

