/**
 * Send a notification: store in-memory, route to the appropriate channel
 * (respecting user preferences), and log to audit service.
 */
private sendNotification(params: {
  type: string;
  recipient: string;
  subject: string;
  body: string;
  priority: NotificationPriority;
}): void {
  const notification: Notification = {
    id: generateNotificationId(),
    recipient: params.recipient,
    subject: params.subject,
    body: params.body,
    sentAt: new Date(),
  };
  this.notifications.push(notification);
  this.logger.info(`Notification sent: ${notification.id} to ${params.recipient} [${params.priority}]`);

  const event: NotificationEvent = {
    type: params.type,
    recipient: params.recipient,
    subject: params.subject,
    body: params.body,
    priority: params.priority,
  };

  // Check user preferences for a channel override
  let channelUsed: string = params.priority;
  const preferredChannel = this.preferencesService?.getPreference(
    params.recipient,
    params.priority,
  );

  if (preferredChannel && this.channelRegistry.has(preferredChannel)) {
    const channel = this.channelRegistry.get(preferredChannel)!;
    void Promise.resolve(channel.handle(event));
    channelUsed = preferredChannel;
    this.logger.info(
      `Routed via user preference: ${params.recipient} → ${preferredChannel}`,
    );
  } else if (this.priorityRouter) {
    void this.priorityRouter.route({ ...event, priority: params.priority });
    channelUsed = params.priority;
  }

  // Audit log
  if (this.auditService) {
    this.auditService.log({
      notificationType: params.type,
      recipient: params.recipient,
      subject: params.subject,
      body: params.body,
      priority: params.priority,
      channel: channelUsed,
    });
  }
}

