import { describe, it, expect, beforeEach } from 'vitest';
import { AuditService, resetAuditIdCounter } from '../../src/services/audit.service.js';

describe('AuditService', () => {
  let audit: AuditService;

  beforeEach(() => {
    audit = new AuditService();
    resetAuditIdCounter();
  });

  it('should log an audit entry and return it', () => {
    const entry = audit.log({
      notificationType: 'order:confirmation',
      recipient: 'alice@example.com',
      subject: 'Order Confirmed',
      body: 'Your order is confirmed.',
      priority: 'normal',
      channel: 'email',
    });

    expect(entry.id).toBe('audit-0001');
    expect(entry.notificationType).toBe('order:confirmation');
    expect(entry.recipient).toBe('alice@example.com');
    expect(entry.channel).toBe('email');
    expect(entry.timestamp).toBeInstanceOf(Date);
  });

  it('should generate sequential IDs', () => {
    const e1 = audit.log({
      notificationType: 'a',
      recipient: 'a@b.com',
      subject: 's',
      body: 'b',
      priority: 'normal',
      channel: 'email',
    });
    const e2 = audit.log({
      notificationType: 'b',
      recipient: 'c@d.com',
      subject: 's',
      body: 'b',
      priority: 'urgent',
      channel: 'sms',
    });

    expect(e1.id).toBe('audit-0001');
    expect(e2.id).toBe('audit-0002');
  });

  it('should return all entries', () => {
    audit.log({
      notificationType: 'a',
      recipient: 'a@b.com',
      subject: 's',
      body: 'b',
      priority: 'normal',
      channel: 'email',
    });
    audit.log({
      notificationType: 'b',
      recipient: 'c@d.com',
      subject: 's',
      body: 'b',
      priority: 'urgent',
      channel: 'sms',
    });

    expect(audit.getEntries()).toHaveLength(2);
    expect(audit.getEntryCount()).toBe(2);
  });

  it('should filter entries by recipient', () => {
    audit.log({
      notificationType: 'a',
      recipient: 'alice@example.com',
      subject: 's',
      body: 'b',
      priority: 'normal',
      channel: 'email',
    });
    audit.log({
      notificationType: 'b',
      recipient: 'bob@example.com',
      subject: 's',
      body: 'b',
      priority: 'urgent',
      channel: 'sms',
    });

    expect(audit.getEntriesForRecipient('alice@example.com')).toHaveLength(1);
    expect(audit.getEntriesForRecipient('bob@example.com')).toHaveLength(1);
    expect(audit.getEntriesForRecipient('nobody@example.com')).toHaveLength(0);
  });

  it('should filter entries by channel', () => {
    audit.log({
      notificationType: 'a',
      recipient: 'a@b.com',
      subject: 's',
      body: 'b',
      priority: 'normal',
      channel: 'email',
    });
    audit.log({
      notificationType: 'b',
      recipient: 'c@d.com',
      subject: 's',
      body: 'b',
      priority: 'urgent',
      channel: 'sms',
    });

    expect(audit.getEntriesByChannel('email')).toHaveLength(1);
    expect(audit.getEntriesByChannel('sms')).toHaveLength(1);
    expect(audit.getEntriesByChannel('webhook')).toHaveLength(0);
  });

  it('should filter entries by priority', () => {
    audit.log({
      notificationType: 'a',
      recipient: 'a@b.com',
      subject: 's',
      body: 'b',
      priority: 'normal',
      channel: 'email',
    });
    audit.log({
      notificationType: 'b',
      recipient: 'c@d.com',
      subject: 's',
      body: 'b',
      priority: 'urgent',
      channel: 'sms',
    });

    expect(audit.getEntriesByPriority('normal')).toHaveLength(1);
    expect(audit.getEntriesByPriority('urgent')).toHaveLength(1);
    expect(audit.getEntriesByPriority('low')).toHaveLength(0);
  });

  it('should clear all entries', () => {
    audit.log({
      notificationType: 'a',
      recipient: 'a@b.com',
      subject: 's',
      body: 'b',
      priority: 'normal',
      channel: 'email',
    });

    audit.clear();
    expect(audit.getEntries()).toHaveLength(0);
    expect(audit.getEntryCount()).toBe(0);
  });
});

import { describe, it, expect, beforeEach } from 'vitest';
import { NotificationPreferencesService } from '../../src/services/notification-preferences.service.js';

describe('NotificationPreferencesService', () => {
  let prefs: NotificationPreferencesService;

  beforeEach(() => {
    prefs = new NotificationPreferencesService();
  });

  it('should return undefined when no preference is set', () => {
    expect(prefs.getPreference('user-1', 'urgent')).toBeUndefined();
  });

  it('should set and get a preference', () => {
    prefs.setPreference('user-1', 'urgent', 'email');
    expect(prefs.getPreference('user-1', 'urgent')).toBe('email');
  });

  it('should override an existing preference', () => {
    prefs.setPreference('user-1', 'urgent', 'email');
    prefs.setPreference('user-1', 'urgent', 'webhook');
    expect(prefs.getPreference('user-1', 'urgent')).toBe('webhook');
  });

  it('should keep preferences independent per user', () => {
    prefs.setPreference('user-1', 'urgent', 'email');
    prefs.setPreference('user-2', 'urgent', 'webhook');

    expect(prefs.getPreference('user-1', 'urgent')).toBe('email');
    expect(prefs.getPreference('user-2', 'urgent')).toBe('webhook');
  });

  it('should keep preferences independent per priority', () => {
    prefs.setPreference('user-1', 'urgent', 'email');
    prefs.setPreference('user-1', 'normal', 'webhook');

    expect(prefs.getPreference('user-1', 'urgent')).toBe('email');
    expect(prefs.getPreference('user-1', 'normal')).toBe('webhook');
    expect(prefs.getPreference('user-1', 'low')).toBeUndefined();
  });

  it('should remove a specific preference', () => {
    prefs.setPreference('user-1', 'urgent', 'email');
    const removed = prefs.removePreference('user-1', 'urgent');

    expect(removed).toBe(true);
    expect(prefs.getPreference('user-1', 'urgent')).toBeUndefined();
  });

  it('should return false when removing nonexistent preference', () => {
    expect(prefs.removePreference('user-1', 'urgent')).toBe(false);
  });

  it('should return all preferences for a user', () => {
    prefs.setPreference('user-1', 'urgent', 'email');
    prefs.setPreference('user-1', 'low', 'sms');

    const userPrefs = prefs.getUserPreferences('user-1');
    expect(userPrefs.size).toBe(2);
    expect(userPrefs.get('urgent')).toBe('email');
    expect(userPrefs.get('low')).toBe('sms');
  });

  it('should return empty map for unknown user', () => {
    expect(prefs.getUserPreferences('unknown').size).toBe(0);
  });

  it('should clear preferences for a specific user', () => {
    prefs.setPreference('user-1', 'urgent', 'email');
    prefs.setPreference('user-2', 'urgent', 'sms');

    prefs.clearPreferences('user-1');

    expect(prefs.getPreference('user-1', 'urgent')).toBeUndefined();
    expect(prefs.getPreference('user-2', 'urgent')).toBe('sms');
  });

  it('should clear all preferences', () => {
    prefs.setPreference('user-1', 'urgent', 'email');
    prefs.setPreference('user-2', 'normal', 'sms');

    prefs.clear();

    expect(prefs.getPreference('user-1', 'urgent')).toBeUndefined();
    expect(prefs.getPreference('user-2', 'normal')).toBeUndefined();
  });
});

import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import {
  NotificationService,
  EmailNotificationChannel,
  SmsNotificationChannel,
  WebhookNotificationChannel,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import { PriorityRouter } from '../../src/services/priority-router.js';
import { AuditService, resetAuditIdCounter } from '../../src/services/audit.service.js';
import { NotificationPreferencesService } from '../../src/services/notification-preferences.service.js';
import { statusChangeCallbacks } from '../../src/utils/callback-registry.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';

describe('Notification Flow Integration', () => {
  let eventBus: EventBus;
  let router: PriorityRouter;
  let emailChannel: EmailNotificationChannel;
  let smsChannel: SmsNotificationChannel;
  let webhookChannel: WebhookNotificationChannel;
  let auditService: AuditService;
  let preferencesService: NotificationPreferencesService;
  let service: NotificationService;

  beforeEach(() => {
    eventBus = new EventBus();
    statusChangeCallbacks.clear();

    emailChannel = new EmailNotificationChannel();
    smsChannel = new SmsNotificationChannel();
    webhookChannel = new WebhookNotificationChannel();

    router = new PriorityRouter();
    router.registerRoute('urgent', smsChannel);
    router.registerRoute('normal', emailChannel);
    router.registerRoute('low', webhookChannel);

    auditService = new AuditService();
    preferencesService = new NotificationPreferencesService();

    service = new NotificationService(eventBus, router, auditService, preferencesService);
    service.registerChannel('email', emailChannel);
    service.registerChannel('sms', smsChannel);
    service.registerChannel('webhook', webhookChannel);

    resetNotificationIdCounter();
    resetAuditIdCounter();
  });

  function makeOrderCreatedEvent(overrides?: Partial<OrderCreatedEvent>): OrderCreatedEvent {
    return {
      type: 'order:created',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [{ productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 }],
        total: 20,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
      ...overrides,
    };
  }

  function makeStatusChangedEvent(
    overrides?: Partial<OrderStatusChangedEvent>,
  ): OrderStatusChangedEvent {
    return {
      type: 'order:status-changed',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [],
        total: 20,
        status: 'confirmed',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      previousStatus: 'pending',
      newStatus: 'confirmed',
      timestamp: new Date(),
      ...overrides,
    };
  }

  describe('priority routing → channel selection → audit log', () => {
    it('should route normal-priority order confirmation to email and create audit entry', async () => {
      await eventBus.emit(makeOrderCreatedEvent());

      // Channel selection: normal → email
      expect(emailChannel.getDeliveredEmails()).toHaveLength(1);
      expect(smsChannel.getDeliveredMessages()).toHaveLength(0);
      expect(webhookChannel.getDeliveredPayloads()).toHaveLength(0);

      // Audit log entry
      const entries = auditService.getEntries();
      expect(entries).toHaveLength(1);
      expect(entries[0]?.notificationType).toBe('order:confirmation');
      expect(entries[0]?.recipient).toBe('alice@example.com');
      expect(entries[0]?.priority).toBe('normal');
      expect(entries[0]?.channel).toBe('normal');
    });

    it('should route urgent status update to SMS and create audit entry', () => {
      statusChangeCallbacks.notify(makeStatusChangedEvent());

      // Channel selection: urgent → SMS
      expect(smsChannel.getDeliveredMessages()).toHaveLength(1);
      expect(emailChannel.getDeliveredEmails()).toHaveLength(0);
      expect(webhookChannel.getDeliveredPayloads()).toHaveLength(0);

      // Audit log entry
      const entries = auditService.getEntries();
      expect(entries).toHaveLength(1);
      expect(entries[0]?.notificationType).toBe('order:status-update');
      expect(entries[0]?.recipient).toBe('user-1');
      expect(entries[0]?.priority).toBe('urgent');
      expect(entries[0]?.channel).toBe('urgent');
    });

    it('should create audit entries for multiple notifications', async () => {
      await eventBus.emit(makeOrderCreatedEvent());
      statusChangeCallbacks.notify(makeStatusChangedEvent());

      expect(auditService.getEntryCount()).toBe(2);
      expect(auditService.getEntries()[0]?.id).toBe('audit-0001');
      expect(auditService.getEntries()[1]?.id).toBe('audit-0002');
    });
  });

  describe('user preferences override priority routing', () => {
    it('should route urgent notification to email when user prefers email for urgent', () => {
      preferencesService.setPreference('user-1', 'urgent', 'email');

      statusChangeCallbacks.notify(makeStatusChangedEvent());

      // Overridden: urgent goes to email instead of SMS
      expect(emailChannel.getDeliveredEmails()).toHaveLength(1);
      expect(smsChannel.getDeliveredMessages()).toHaveLength(0);
      expect(webhookChannel.getDeliveredPayloads()).toHaveLength(0);

      // Audit should record the overridden channel
      const entries = auditService.getEntries();
      expect(entries).toHaveLength(1);
      expect(entries[0]?.channel).toBe('email');
      expect(entries[0]?.priority).toBe('urgent');
    });

    it('should route normal notification to webhook when user prefers webhook', async () => {
      preferencesService.setPreference('alice@example.com', 'normal', 'webhook');

      await eventBus.emit(makeOrderCreatedEvent());

      // Overridden: normal goes to webhook instead of email
      expect(webhookChannel.getDeliveredPayloads()).toHaveLength(1);
      expect(emailChannel.getDeliveredEmails()).toHaveLength(0);
      expect(smsChannel.getDeliveredMessages()).toHaveLength(0);

      const entries = auditService.getEntries();
      expect(entries[0]?.channel).toBe('webhook');
    });

    it('should fall back to priority routing when no user preference is set', async () => {
      // No preferences set for alice
      await eventBus.emit(makeOrderCreatedEvent());

      // Default: normal → email
      expect(emailChannel.getDeliveredEmails()).toHaveLength(1);
      expect(smsChannel.getDeliveredMessages()).toHaveLength(0);
    });

    it('should fall back to priority routing when preference channel is not registered', () => {
      // Set a preference but don't register that channel type
      const isolatedService = new NotificationService(
        eventBus,
        router,
        auditService,
        preferencesService,
      );
      // Don't call registerChannel — channel registry is empty
      preferencesService.setPreference('user-1', 'urgent', 'webhook');

      statusChangeCallbacks.notify(makeStatusChangedEvent());

      // Falls back to priority routing: urgent → SMS
      expect(smsChannel.getDeliveredMessages()).toHaveLength(1);

      void isolatedService;
    });

    it('should handle mixed preferences across multiple users', async () => {
      preferencesService.setPreference('alice@example.com', 'normal', 'sms');

      // Alice's order → normal priority → user pref overrides to SMS
      await eventBus.emit(makeOrderCreatedEvent());

      expect(smsChannel.getDeliveredMessages()).toHaveLength(1);
      expect(emailChannel.getDeliveredEmails()).toHaveLength(0);

      // Bob's order → normal priority → no preference → default email
      await eventBus.emit(
        makeOrderCreatedEvent({
          user: {
            id: 'user-2',
            name: 'Bob',
            email: 'bob@example.com',
            role: 'member',
            createdAt: new Date(),
            updatedAt: new Date(),
          },
        }),
      );

      expect(emailChannel.getDeliveredEmails()).toHaveLength(1);
      expect(smsChannel.getDeliveredMessages()).toHaveLength(1); // still just Alice's

      // Both should have audit entries
      expect(auditService.getEntryCount()).toBe(2);
    });
  });

  describe('full end-to-end flow', () => {
    it('should handle order lifecycle: creation + status change with audit trail', async () => {
      // Step 1: Order created → normal → email
      await eventBus.emit(makeOrderCreatedEvent());

      // Step 2: Status changed → urgent → SMS
      statusChangeCallbacks.notify(makeStatusChangedEvent());

      // Verify notifications stored
      expect(service.getNotificationCount()).toBe(2);

      // Verify channel delivery
      expect(emailChannel.getDeliveredEmails()).toHaveLength(1);
      expect(smsChannel.getDeliveredMessages()).toHaveLength(1);
      expect(webhookChannel.getDeliveredPayloads()).toHaveLength(0);

      // Verify complete audit trail
      const auditEntries = auditService.getEntries();
      expect(auditEntries).toHaveLength(2);

      expect(auditEntries[0]?.notificationType).toBe('order:confirmation');
      expect(auditEntries[0]?.priority).toBe('normal');

      expect(auditEntries[1]?.notificationType).toBe('order:status-update');
      expect(auditEntries[1]?.priority).toBe('urgent');
    });

    it('should handle order lifecycle with user preferences overriding routing', async () => {
      // Alice prefers all urgent notifications via email
      preferencesService.setPreference('user-1', 'urgent', 'email');

      // Order created → normal → email (default)
      await eventBus.emit(makeOrderCreatedEvent());

      // Status changed → urgent → email (overridden from SMS)
      statusChangeCallbacks.notify(makeStatusChangedEvent());

      // Both went to email
      expect(emailChannel.getDeliveredEmails()).toHaveLength(2);
      expect(smsChannel.getDeliveredMessages()).toHaveLength(0);

      // Audit trail reflects the override
      const auditEntries = auditService.getEntries();
      expect(auditEntries[1]?.channel).toBe('email');
      expect(auditEntries[1]?.priority).toBe('urgent');
    });
  });
});

