+ * capturing the notification details, priority, and channel used.
+ */
+
+import type { NotificationPriority } from './priority-router.js';
+
+export interface AuditEntry {
+  id: string;
+  timestamp: Date;
+  notificationType: string;
+  recipient: string;
+  subject: string;
+  body: string;
+  priority: NotificationPriority;
+  channel: string;
+}
+
+let nextAuditId = 1;
+
+function generateAuditId(): string {
+  return `audit-${String(nextAuditId++).padStart(4, '0')}`;
+}
+
+export function resetAuditIdCounter(): void {
+  nextAuditId = 1;
+}
+
+export class AuditService {
+  private entries: AuditEntry[] = [];
+
+  log(params: {
+    notificationType: string;
+    recipient: string;
+    subject: string;
+    body: string;
+    priority: NotificationPriority;
+    channel: string;
+  }): AuditEntry {
+    const entry: AuditEntry = {
+      id: generateAuditId(),
+      timestamp: new Date(),
+      ...params,
+    };
+    this.entries.push(entry);
+    return entry;
+  }
+
+  getEntries(): AuditEntry[] {
+    return [...this.entries];
+  }
+
+  getEntriesForRecipient(recipient: string): AuditEntry[] {
+    return this.entries.filter((e) => e.recipient === recipient);
+  }
+
+  getEntriesByChannel(channel: string): AuditEntry[] {
+    return this.entries.filter((e) => e.channel === channel);
+  }
+
+  getEntriesByPriority(priority: NotificationPriority): AuditEntry[] {
+    return this.entries.filter((e) => e.priority === priority);
+  }
+
+  getEntryCount(): number {
+    return this.entries.length;
+  }
+
+  clear(): void {
+    this.entries = [];
+  }
+}

