+/**
+ * Notification preferences service.
+ *
+ * Allows per-user channel preferences that override the default
+ * priority-based routing. For example, a user can choose to receive
+ * all urgent notifications via email instead of SMS.
+ */
+
+import type { NotificationPriority } from './priority-router.js';
+
+export type ChannelType = 'email' | 'sms' | 'webhook';
+
+export class NotificationPreferencesService {
+  private preferences = new Map<string, Map<NotificationPriority, ChannelType>>();
+
+  setPreference(userId: string, priority: NotificationPriority, channel: ChannelType): void {
+    let userPrefs = this.preferences.get(userId);
+    if (!userPrefs) {
+      userPrefs = new Map();
+      this.preferences.set(userId, userPrefs);
+    }
+    userPrefs.set(priority, channel);
+  }
+
+  getPreference(userId: string, priority: NotificationPriority): ChannelType | undefined {
+    return this.preferences.get(userId)?.get(priority);
+  }
+
+  removePreference(userId: string, priority: NotificationPriority): boolean {
+    const userPrefs = this.preferences.get(userId);
+    if (!userPrefs) return false;
+    const deleted = userPrefs.delete(priority);
+    if (userPrefs.size === 0) {
+      this.preferences.delete(userId);
+    }
+    return deleted;
+  }
+
+  getUserPreferences(userId: string): Map<NotificationPriority, ChannelType> {
+    return new Map(this.preferences.get(userId) ?? []);
+  }
+
+  clearPreferences(userId: string): void {
+    this.preferences.delete(userId);
+  }
+
+  clear(): void {
+    this.preferences.clear();
+  }
+}

